  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { Flex, FlexItem, PageSection, Title } from '@patternfly/react-core';
  4	import PipelineRunsStatusCard from './PipelineRunsStatusCard';
  5	import {
  6	  useActiveNamespace,
  7	  useFlag,
  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import PipelinesRunsDurationCard from './PipelineRunsDurationCard';
 10	import PipelinesRunsTotalCard from './PipelineRunsTotalCard';
 11	import PipelinesRunsNumbersChart from './PipelineRunsNumbersChart';
 12	import { formatPrometheusDuration, parsePrometheusDuration } from './dateTime';
 13	import NameSpaceDropdown from './NamespaceDropdown';
 14	import PipelineRunsListPage from './list-pages/PipelineRunsListPage';
 15	import TimeRangeDropdown from './TimeRangeDropdown';
 16	import RefreshDropdown from './RefreshDropdown';
 17	import { IntervalOptions, TimeRangeOptions } from './utils';
 18	import { ALL_NAMESPACES_KEY } from '../../consts';
 19	import AllProjectsPage from '../projects-list/AllProjectsPage';
 20	import { FLAGS } from '../../types';
 21	import {
 22	  usePersistedTimespanWithUrl,
 23	  usePersistedIntervalWithUrl,
 24	} from '../hooks/usePersistedFiltersForPipelineOverview';
 25	
 26	const PipelinesOverviewPage: React.FC = () => {
 27	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 28	  const canListNS = useFlag(FLAGS.CAN_LIST_NS);
 29	  const [activeNamespace, setActiveNamespace] = useActiveNamespace();
 30	
 31	  const [timespan, setTimespan] = usePersistedTimespanWithUrl(
 32	    parsePrometheusDuration('1d'),
 33	    {
 34	      options: TimeRangeOptions(),
 35	      displayFormat: formatPrometheusDuration,
 36	      loadFormat: parsePrometheusDuration,
 37	    },
 38	    activeNamespace,
 39	  );
 40	
 41	  const [interval, setInterval] = usePersistedIntervalWithUrl(
 42	    parsePrometheusDuration('30s'),
 43	    {
 44	      options: { ...IntervalOptions(), off: 'OFF_KEY' },
 45	      displayFormat: (v) => (v ? formatPrometheusDuration(v) : 'off'),
 46	      loadFormat: (v) => (v == 'off' ? null : parsePrometheusDuration(v)),
 47	    },
 48	    activeNamespace,
 49	  );
 50	
 51	  if (!canListNS && activeNamespace === ALL_NAMESPACES_KEY) {
 52	    return <AllProjectsPage pageTitle={t('Overview')} />;
 53	  }
 54	
 55	  return (
 56	    <>
 57	      <PageSection variant="light" className="pf-v6-u-pl-md">
 58	        <Title headingLevel="h2">{t('Overview')}</Title>
 59	      </PageSection>
 60	      <Flex className="project-dropdown-label__flex pf-v6-u-mt-md">
 61	        <FlexItem>
 62	          <NameSpaceDropdown
 63	            selected={activeNamespace}
 64	            setSelected={setActiveNamespace}
 65	          />
 66	        </FlexItem>
 67	        <FlexItem>
 68	          <TimeRangeDropdown timespan={timespan} setTimespan={setTimespan} />
 69	        </FlexItem>
 70	        <FlexItem>
 71	          <RefreshDropdown interval={interval} setInterval={setInterval} />
 72	        </FlexItem>
 73	      </Flex>
 74	      <div className="pipeline-overview__duration-total-plr-grid">
 75	        <PipelineRunsStatusCard
 76	          timespan={timespan}
 77	          domain={{ y: [0, 100] }}
 78	          bordered={true}
 79	          namespace={activeNamespace}
 80	          interval={interval}
 81	        />
 82	
 83	        <Flex>
 84	          <FlexItem
 85	            spacer={{ default: 'spacerXs' }}
 86	            grow={{ default: 'grow' }}
 87	            className="pipelines-overview__cards"
 88	          >
 89	            <PipelinesRunsDurationCard
 90	              namespace={activeNamespace}
 91	              timespan={timespan}
 92	              interval={interval}
 93	              bordered={true}
 94	            />
 95	          </FlexItem>
 96	          <FlexItem
 97	            spacer={{ default: 'spacerXs' }}
 98	            grow={{ default: 'grow' }}
 99	            className="pipelines-overview__cards"
100	          >
101	            <PipelinesRunsTotalCard
102	              namespace={activeNamespace}
103	              timespan={timespan}
104	              interval={interval}
105	              bordered={true}
106	            />
107	          </FlexItem>
108	          <FlexItem
109	            grow={{ default: 'grow' }}
110	            className="pipelines-overview__cards"
111	          >
112	            <PipelinesRunsNumbersChart
113	              namespace={activeNamespace}
114	              timespan={timespan}
115	              interval={interval}
116	              domain={{ y: [0, 500] }}
117	              bordered={true}
118	            />
119	          </FlexItem>
120	        </Flex>
121	
122	        <PipelineRunsListPage
123	          namespace={activeNamespace}
124	          timespan={timespan}
125	          interval={interval}
126	          bordered
127	        />
128	      </div>
129	    </>
130	  );
131	};
132	
133	export default PipelinesOverviewPage;

